DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'warestockforsales' AND column_name = 'price') THEN EXECUTE 'COMMENT ON COLUMN warestockforsales.price IS ''  批次单价 用于先进先出 后进先出法 的成本计算'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'warestockforsales' AND column_name = 'total') THEN EXECUTE 'COMMENT ON COLUMN warestockforsales.total IS ''成本合计'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'warestockforsales' AND column_name = 'order') THEN EXECUTE 'COMMENT ON COLUMN warestockforsales.order IS ''  批次 用于先进先出 后进先出法 的成本计算(暂时没启用)'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'warestockforsales' AND column_name = 'stockdate') THEN EXECUTE 'COMMENT ON COLUMN warestockforsales.stockdate IS ''更新原材料信息日期'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'warestockforsales' AND column_name = 'number2') THEN EXECUTE 'COMMENT ON COLUMN warestockforsales.number2 IS ''计量单位2数量'''; END IF; END $$;
DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_name = 'audit_employees') THEN EXECUTE 'COMMENT ON TABLE audit_employees IS ''CREATE TABLE AUDIT_EMPLOYEES  /*审核级别 最多5级'''; END IF; END $$;
